const survives = (count: number, wasAlive: boolean): boolean =>
  count === 3 || (count === 2 && wasAlive);

type NeighborTally = { cell: Cell; count: number };

const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

export function nextGeneration(livingCells: Cell[]): Cell[] {
  const aliveKeys = new Set(livingCells.map(cellKey));
  const tallies = new Map<string, NeighborTally>();

  for (const cell of livingCells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = cellKey(neighbor);
      const existing = tallies.get(k);
      tallies.set(k, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
    }
  }

  return Array.from(tallies.values())
    .filter(({ cell, count }) => survives(count, aliveKeys.has(cellKey(cell))))
    .map(({ cell }) => cell);
}

