const survives = (neighborCount: number, wasAlive: boolean): boolean =>
  neighborCount === 3 || (neighborCount === 2 && wasAlive);

const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

export function nextGeneration(livingCells: Cell[]): Cell[] {
  const aliveKeys = new Set(livingCells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const livingCell of livingCells) {
    for (const neighbor of neighborsOf(livingCell)) {
      const key = cellKey(neighbor);
      const entry = neighborCounts.get(key) ?? { cell: neighbor, count: 0 };
      entry.count += 1;
      neighborCounts.set(key, entry);
    }
  }

  const survivors: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    if (survives(count, aliveKeys.has(key))) survivors.push(cell);
  }
  return survivors;
}
